from pydantic import BaseModel, Field
from typing import Optional, Any
from vex_sdk import VexDriftCapture

class DriftAwareResponse(BaseModel):
    content: str
    is_drifted: bool = False
    drift_reason: Optional[str] = None

class SafeAgent(Agent):
    def __init__(self):
        super().__init__(
            result_validator=self._drift_aware_validator
        )

    def _drift_aware_validator(self, response: Any) -> Optional[DriftAwareResponse]:
        try:
            return StrictReport.model_validate(response)
        except Exception as e:
            VexDriftCapture.log_raw_response(response, str(e))
            return DriftAwareResponse(
                content=str(response),
                is_drifted=True,
                drift_reason=str(e)
            )

