from pydantic_ai.streaming import StreamingAgent

class ResilientStreamer(StreamingAgent):
    async def _validate_stream_chunk(self, chunk: str, partial: bool = False):
        if partial:
            # Lenient validation for partial chunks
            return PartialReport.try_validate(chunk)
        return StreamingReport.model_validate(chunk)

    async def stream_with_recovery(self, prompt: str):
        buffer = ''
        async for chunk in self._raw_stream(prompt):
            buffer += chunk
            validated = await self._validate_stream_chunk(buffer, partial=True)
            if validated:
                yield validated
                buffer = ''  # Reset on successful validation
